import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import {
	createServer,
	type IncomingMessage,
	type ServerResponse,
} from "node:http";
import { execFile } from "node:child_process";
import { existsSync } from "node:fs";
import { readdir, readFile, stat } from "node:fs/promises";
import { basename, join, relative, resolve } from "node:path";
import { homedir } from "node:os";
import { promisify } from "node:util";
import { commandrBus, gitSnapshot, readJsonObject } from "./git-helpers";

const execFileAsync = promisify(execFile);

interface ControlConfig {
	controlPlane?: {
		enabled?: boolean;
		host?: string;
		port?: number;
		openBrowser?: boolean;
		multiRepo?: boolean;
	};
	obsidianVault?: string;
	obsidianCli?: string;
	obsidianFolders?: Record<string, string>;
	gitview?: { staleDays?: number; historyDepth?: number };
}

let server: ReturnType<typeof createServer> | undefined;
let serverUrl = "";

async function readConfig(cwd: string): Promise<ControlConfig> {
	const cfg: Record<string, unknown> = {};
	Object.assign(
		cfg,
		await readJsonObject(
			join(homedir(), ".config", "agent-workflow", "config.json"),
		),
	);
	try {
		const { stdout } = await execFileAsync(
			"git",
			["-C", cwd, "rev-parse", "--git-common-dir"],
			{ timeout: 2000 },
		);
		let common = stdout.trim();
		if (!common.startsWith("/")) common = resolve(cwd, common);
		const root = common
			.replace(/\/\.git$/, "")
			.replace(/\/\.git\/worktrees\/[^/]+$/, "");
		Object.assign(
			cfg,
			await readJsonObject(join(root, ".agent-workflow.json")),
		);
		Object.assign(
			cfg,
			await readJsonObject(join(root, ".agent-workflow.local.json")),
		);
	} catch {
		/* ignore */
	}
	return cfg as ControlConfig;
}

function sendJson(res: ServerResponse, status: number, body: unknown): void {
	res.writeHead(status, { "content-type": "application/json; charset=utf-8" });
	res.end(JSON.stringify(body, null, 2));
}

function sendHtml(res: ServerResponse, body: string): void {
	res.writeHead(200, { "content-type": "text/html; charset=utf-8" });
	res.end(body);
}

async function laneFiles(dir: string): Promise<string[]> {
	try {
		return (await readdir(dir)).filter((x) => x.endsWith(".md")).sort();
	} catch {
		return [];
	}
}

async function commandrTasks(cwd: string) {
	const bus = await commandrBus(cwd);
	if (!bus) return { bus: null, inbox: [], claimed: [], done: [] };
	return {
		bus,
		inbox: await laneFiles(join(bus, "inbox")),
		claimed: await laneFiles(join(bus, "claimed")),
		done: await laneFiles(join(bus, "done")),
	};
}

async function commandrEvents(cwd: string) {
	const bus = await commandrBus(cwd);
	if (!bus) return [];
	try {
		const raw = await readFile(join(bus, "events.jsonl"), "utf8");
		return raw
			.split("\n")
			.filter(Boolean)
			.slice(-200)
			.flatMap((line) => {
				try {
					return [JSON.parse(line)];
				} catch {
					return [{ parse_error: line }];
				}
			});
	} catch {
		return [];
	}
}

function expandVault(path?: string): string {
	return resolve((path || "~/repos/Obsidian").replace(/^~(?=\/|$)/, homedir()));
}

async function obsidianNotes(cfg: ControlConfig) {
	const vault = expandVault(cfg.obsidianVault);
	const folders = Object.values(
		cfg.obsidianFolders || {
			spec: "Sessions/Specs",
			plan: "Sessions/Plans",
			review: "Sessions/Reviews",
			note: "Sessions/Inbox",
		},
	);
	const seen = new Set<string>();
	const notes: Array<{
		path: string;
		name: string;
		mtime: string;
		size: number;
	}> = [];
	for (const folder of folders) {
		if (seen.has(folder)) continue;
		seen.add(folder);
		const dir = join(vault, folder);
		if (!existsSync(dir)) continue;
		for (const file of await readdir(dir)) {
			if (!file.endsWith(".md")) continue;
			const abs = join(dir, file);
			const st = await stat(abs);
			notes.push({
				path: relative(vault, abs),
				name: file,
				mtime: st.mtime.toISOString(),
				size: st.size,
			});
		}
	}
	return notes.sort((a, b) => b.mtime.localeCompare(a.mtime)).slice(0, 100);
}

async function obsidianCli(cfg: ControlConfig, vault: string, args: string[]) {
	const candidates = [cfg.obsidianCli, "obsidian", "obsidian-cli"].filter(
		Boolean,
	) as string[];
	for (const cli of candidates) {
		try {
			const { stdout } = await execFileAsync(cli, args, {
				cwd: vault,
				timeout: 5000,
				maxBuffer: 4 * 1024 * 1024,
			});
			return { ok: true, stdout };
		} catch {
			/* try next */
		}
	}
	return { ok: false, stdout: "", error: "Obsidian CLI not found" };
}

function page(): string {
	return `<!doctype html>
<html><head><meta charset="utf-8"><title>Pi Cockpit</title>
<style>
body{font:14px ui-monospace,SFMono-Regular,Menlo,monospace;background:#1e2030;color:#cad3f5;margin:0;padding:16px}h1{margin:0 0 12px}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.card{background:#24273a;border:1px solid #494d64;border-radius:8px;padding:12px;min-height:220px;overflow:auto}button{background:#8aadf4;color:#111;border:0;border-radius:4px;padding:4px 8px}pre{white-space:pre-wrap}.muted{color:#6e738d}.item{border-bottom:1px solid #363a4f;padding:4px 0}</style>
</head><body><h1>Pi Local Cockpit</h1><p class="muted">Commandr bus • Git worktrees • Obsidian notes</p><div class="grid"><div class="card"><h2>Commandr</h2><pre id="tasks">loading…</pre></div><div class="card"><h2>Git</h2><pre id="git">loading…</pre></div><div class="card"><h2>Obsidian Notes</h2><div id="notes">loading…</div></div></div><div class="card" style="margin-top:12px"><h2>Events</h2><pre id="events">loading…</pre></div>
<script>
async function j(url){const r=await fetch(url);return r.json()}
async function refresh(){
 const [tasks,git,notes,events]=await Promise.all([j('/api/commandr/tasks'),j('/api/git/worktrees'),j('/api/obsidian/notes'),j('/api/commandr/events')]);
 document.getElementById('tasks').textContent=JSON.stringify(tasks,null,2);
 document.getElementById('git').textContent=JSON.stringify({defaultBranch:git.defaultBranch,worktrees:git.worktrees?.map(w=>({path:w.relPath,branch:w.branch,dirty:w.dirty,stale:w.stale,age:w.lastCommitRelative}))},null,2);
 document.getElementById('events').textContent=JSON.stringify(events.slice(-50),null,2);
 document.getElementById('notes').innerHTML=notes.map(n=>'<div class="item"><button onclick="openNote(''+encodeURIComponent(n.path)+'')">open</button> '+n.path+'<br><span class="muted">'+n.mtime+' • '+n.size+' bytes</span></div>').join('')||'none';
}
async function openNote(p){await fetch('/api/obsidian/open-note',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({path:decodeURIComponent(p)})});}
refresh(); setInterval(refresh,5000);
</script></body></html>`;
}

async function readBody(
	req: IncomingMessage,
): Promise<Record<string, unknown>> {
	const chunks: Buffer[] = [];
	for await (const chunk of req) chunks.push(Buffer.from(chunk));
	try {
		return JSON.parse(Buffer.concat(chunks).toString("utf8") || "{}");
	} catch {
		return {};
	}
}

async function route(
	req: IncomingMessage,
	res: ServerResponse,
	cwd: string,
): Promise<void> {
	const cfg = await readConfig(cwd);
	const url = new URL(req.url || "/", "http://localhost");
	if (url.pathname === "/") return sendHtml(res, page());
	if (url.pathname === "/api/health")
		return sendJson(res, 200, { ok: true, cwd, ts: new Date().toISOString() });
	if (url.pathname === "/api/commandr/tasks")
		return sendJson(res, 200, await commandrTasks(cwd));
	if (url.pathname === "/api/commandr/events")
		return sendJson(res, 200, await commandrEvents(cwd));
	if (url.pathname === "/api/git/worktrees")
		return sendJson(res, 200, await gitSnapshot(cwd, cfg.gitview || {}));
	if (url.pathname === "/api/obsidian/notes")
		return sendJson(res, 200, await obsidianNotes(cfg));
	if (url.pathname === "/api/obsidian/history") {
		const vault = expandVault(cfg.obsidianVault);
		const path = url.searchParams.get("path") || "";
		return sendJson(
			res,
			200,
			await obsidianCli(cfg, vault, ["history", `path=${path}`]),
		);
	}
	if (url.pathname === "/api/obsidian/diff") {
		const vault = expandVault(cfg.obsidianVault);
		const path = url.searchParams.get("path") || "";
		const from = url.searchParams.get("from") || "1";
		const to = url.searchParams.get("to");
		return sendJson(
			res,
			200,
			await obsidianCli(cfg, vault, [
				"diff",
				`path=${path}`,
				`from=${from}`,
				...(to ? [`to=${to}`] : []),
			]),
		);
	}
	if (req.method === "POST" && url.pathname === "/api/obsidian/open-note") {
		const body = await readBody(req);
		const vault = expandVault(cfg.obsidianVault);
		return sendJson(
			res,
			200,
			await obsidianCli(cfg, vault, [
				"open",
				`path=${String(body.path || "")}`,
			]),
		);
	}
	if (req.method === "POST" && url.pathname === "/api/obsidian/open-history") {
		const body = await readBody(req);
		const vault = expandVault(cfg.obsidianVault);
		return sendJson(
			res,
			200,
			await obsidianCli(cfg, vault, [
				"history:open",
				`path=${String(body.path || "")}`,
			]),
		);
	}
	return sendJson(res, 404, { error: "not found" });
}

async function startControlPlane(ctx: any): Promise<string> {
	if (server) return serverUrl;
	const cfg = await readConfig(ctx.cwd);
	const host = cfg.controlPlane?.host || "127.0.0.1";
	const port = cfg.controlPlane?.port || 3340;
	server = createServer(
		(req, res) =>
			void route(req, res, ctx.cwd).catch((error) =>
				sendJson(res, 500, { error: String(error) }),
			),
	);
	await new Promise<void>((resolveListen) =>
		server!.listen(port, host, resolveListen),
	);
	serverUrl = `http://${host}:${port}`;
	if (cfg.controlPlane?.openBrowser !== false) {
		try {
			if (process.platform === "darwin")
				await execFileAsync("open", [serverUrl], { timeout: 5000 });
			else if (process.platform === "linux")
				await execFileAsync("xdg-open", [serverUrl], { timeout: 5000 });
		} catch {
			/* ignore */
		}
	}
	return serverUrl;
}

export default function piControlPlane(pi: ExtensionAPI) {
	pi.registerCommand("control-plane", {
		description: "Start/open local Commandr + DiffViewer + Obsidian cockpit.",
		handler: async (_args, ctx) => {
			const url = await startControlPlane(ctx);
			ctx.ui.notify(`Control plane: ${url}`, "info");
		},
	});
	pi.registerCommand("cockpit", {
		description: "Alias for /control-plane",
		handler: async (_args, ctx) => {
			const url = await startControlPlane(ctx);
			ctx.ui.notify(`Control plane: ${url}`, "info");
		},
	});
}

