	}

	render(width: number): string[] {
		if (this.cachedLines && this.cachedWidth === width) return this.cachedLines;
		const lines: string[] = [];
		lines.push(color("Git Worktrees / Branches", C.lavender) + dim(`  repo ${this.snapshot.repoRoot}`));
