209	async function route(
210		req: IncomingMessage,
211		res: ServerResponse,
212		cwd: string,
213	): Promise<void> {
214		const cfg = await readConfig(cwd);
215		const url = new URL(req.url || "/", "http://localhost");
216		if (url.pathname === "/") return sendHtml(res, page());
217		if (url.pathname === "/api/health")
218			return sendJson(res, 200, { ok: true, cwd, ts: new Date().toISOString() });
219		if (url.pathname === "/api/commandr/tasks")
220			return sendJson(res, 200, await commandrTasks(cwd));
221		if (url.pathname === "/api/commandr/events")
222			return sendJson(res, 200, await commandrEvents(cwd));
223		if (url.pathname === "/api/git/worktrees")
224			return sendJson(res, 200, await gitSnapshot(cwd, cfg.gitview || {}));
225		if (url.pathname === "/api/obsidian/notes")
226			return sendJson(res, 200, await obsidianNotes(cfg));
227		if (url.pathname === "/api/obsidian/history") {
228			const vault = expandVault(cfg.obsidianVault);
229			const path = url.searchParams.get("path") || "";
230			return sendJson(
231				res,
232				200,
233				await obsidianCli(cfg, vault, ["history", `path=${path}`]),
234			);
235		}
236		if (url.pathname === "/api/obsidian/diff") {
237			const vault = expandVault(cfg.obsidianVault);
238			const path = url.searchParams.get("path") || "";
239			const from = url.searchParams.get("from") || "1";
240			const to = url.searchParams.get("to");
241			return sendJson(
242				res,
243				200,
244				await obsidianCli(cfg, vault, [
245					"diff",
246					`path=${path}`,
247					`from=${from}`,
248					...(to ? [`to=${to}`] : []),
249				]),
250			);
251		}
252		if (req.method === "POST" && url.pathname === "/api/obsidian/open-note") {
253			const body = await readBody(req);
254			const vault = expandVault(cfg.obsidianVault);
255			return sendJson(
256				res,
257				200,
258				await obsidianCli(cfg, vault, [
259					"open",
260					`path=${String(body.path || "")}`,
261				]),
262			);
263		}
264		if (req.method === "POST" && url.pathname === "/api/obsidian/open-history") {
265			const body = await readBody(req);
266			const vault = expandVault(cfg.obsidianVault);
267			return sendJson(
268				res,
269				200,
270				await obsidianCli(cfg, vault, [
271					"history:open",
272					`path=${String(body.path || "")}`,
273				]),
274			);
275		}
276		return sendJson(res, 404, { error: "not found" });
277	}
278	
279	async function startControlPlane(ctx: any): Promise<string> {
280		if (server) return serverUrl;
281		const cfg = await readConfig(ctx.cwd);
282		const host = cfg.controlPlane?.host || "127.0.0.1";
283		const port = cfg.controlPlane?.port || 3340;
284		server = createServer(
285			(req, res) =>
286				void route(req, res, ctx.cwd).catch((error) =>
287					sendJson(res, 500, { error: String(error) }),
288				),
289		);
290		await new Promise<void>((resolveListen) =>
291			server!.listen(port, host, resolveListen),
292		);
293		serverUrl = `http://${host}:${port}`;
294		if (cfg.controlPlane?.openBrowser !== false) {
295			try {
296				if (process.platform === "darwin")
297					await execFileAsync("open", [serverUrl], { timeout: 5000 });
298				else if (process.platform === "linux")
299					await execFileAsync("xdg-open", [serverUrl], { timeout: 5000 });
300			} catch {
301				/* ignore */
302			}
303		}
304		return serverUrl;
305	}
306	
307	export default function piControlPlane(pi: ExtensionAPI) {
308		pi.registerCommand("control-plane", {
309			description: "Start/open local Commandr + DiffViewer + Obsidian cockpit.",
310			handler: async (_args, ctx) => {
311				const url = await startControlPlane(ctx);
312				ctx.ui.notify(`Control plane: ${url}`, "info");
313			},
314		});
315		pi.registerCommand("cockpit", {
316			description: "Alias for /control-plane",
317			handler: async (_args, ctx) => {
318				const url = await startControlPlane(ctx);
319				ctx.ui.notify(`Control plane: ${url}`, "info");
320			},
321		});
322	}

