279	async function startControlPlane(ctx: any): Promise<string> {
280		if (server) return serverUrl;
281		const cfg = await readConfig(ctx.cwd);
282		const host = cfg.controlPlane?.host || "127.0.0.1";
283		const port = cfg.controlPlane?.port || 3340;
284		server = createServer(
285			(req, res) =>
286				void route(req, res, ctx.cwd).catch((error) =>
287					sendJson(res, 500, { error: String(error) }),
288				),
289		);
290		await new Promise<void>((resolveListen) =>
291			server!.listen(port, host, resolveListen),
292		);
293		serverUrl = `http://${host}:${port}`;
294		if (cfg.controlPlane?.openBrowser !== false) {
295			try {
296				if (process.platform === "darwin")
297					await execFileAsync("open", [serverUrl], { timeout: 5000 });
298				else if (process.platform === "linux")
299					await execFileAsync("xdg-open", [serverUrl], { timeout: 5000 });
300			} catch {
301				/* ignore */
302			}
303		}
304		return serverUrl;
305	}
