216	async function showGitBrowser(pi: ExtensionAPI, args: string, ctx: any): Promise<void> {
217		const cfg = await readWorkflowConfig(ctx.cwd);
218		const gitCfg = cfg.gitview || {};
219		const staleDays = gitCfg.staleDays ?? 14;
220		const historyDepth = gitCfg.historyDepth ?? 20;
221		const multiRepo = args.includes("--all") || gitCfg.multiRepo === true;
222		const repos = multiRepo && gitCfg.repos?.length ? gitCfg.repos.map((repo) => expandHome(repo, homedir())) : [ctx.cwd];
223		for (const repo of repos) {
224			let doneAction: Action | undefined;
225			const snapshot = await gitSnapshot(repo, { staleDays, historyDepth });
226			if (!ctx.hasUI || ctx.mode !== "tui") {
227				ctx.ui.notify(`worktrees: ${snapshot.worktrees.length}, branches: ${snapshot.branches.length}`, "info");
228				continue;
229			}
230			await ctx.ui.custom<void>((tui: any, _theme: any, _kb: any, done: any) => {
231				const component = new GitBrowser(snapshot, historyDepth, (action) => {
232					doneAction = action;
233					done(undefined);
234				});
235				return {
236					render: (width: number) => component.render(width),
237					invalidate: () => component.invalidate(),
238					handleInput: (data: string) => {
239						component.handleInput(data);
240						tui.requestRender();
241					},
242				};
243			}, { overlay: true, overlayOptions: { width: "90%", maxHeight: "85%", anchor: "center", margin: 1 } });
244			if (!doneAction || doneAction.type === "quit") continue;
245			if (doneAction.type === "refresh") {
246				await showGitBrowser(pi, args, ctx);
247				return;
248			}
249			if (doneAction.type === "open" || doneAction.type === "reveal") {
250				await revealPath(doneAction.path);
251				ctx.ui.notify(`Opened ${doneAction.path}`, "info");
252			}
253			if (doneAction.type === "handoff") {
254				const marker = await writeWorktreeHandoff({ cwd: ctx.cwd, targetWorktree: doneAction.path, action: "operate", sourceSession: ctx.sessionManager?.getSessionFile?.() });
255				pi.sendUserMessage(`Operate in git worktree: ${doneAction.path}\n\nBefore editing, read the handoff marker ${marker}, verify git status/ahead-behind/untracked files, and preserve a backup/checkpoint before destructive operations.`, { deliverAs: "followUp" });
256				ctx.ui.notify(`Queued worktree handoff: ${marker}`, "info");
257			}
258			if (doneAction.type === "prune") {
259				const ok = await ctx.ui.confirm("Prune worktrees?", "Run `git worktree prune` for the current repository? This only removes stale administrative records.");
260				if (ok) {
261					const result = await execCmd("git", ["-C", snapshot.repoRoot, "worktree", "prune", "--verbose"], snapshot.repoRoot, 10000);
262					ctx.ui.notify(result.stdout || result.stderr || "Pruned worktrees", result.code === 0 ? "info" : "warning");
263				}
264			}
265			if (doneAction.type === "remove") {
266				const backup = await backupWorktree(doneAction.path, ctx.sessionManager?.getSessionFile?.());
267				const ok = await ctx.ui.confirm("Remove worktree?", `Backup written to ${backup}\n\nRemove ${doneAction.path}?`);
268				if (ok) {
269					const result = await execCmd("git", ["-C", snapshot.repoRoot, "worktree", "remove", doneAction.path], snapshot.repoRoot, 15000);
270					ctx.ui.notify(result.stdout || result.stderr || "Removed worktree", result.code === 0 ? "info" : "warning");
271				} else {
272					ctx.ui.notify(`Cancelled. Backup remains at ${backup}`, "info");
273				}
274			}
275		}
276	}
