278	export default function piGitView(pi: ExtensionAPI) {
279		pi.registerCommand("worktrees", {
280			description: "Open git worktree/branch viewer. Args: [--all]",
281			handler: async (args, ctx) => showGitBrowser(pi, args || "", ctx),
282		});
283		pi.registerCommand("wt", {
284			description: "Alias for /worktrees",
285			handler: async (args, ctx) => showGitBrowser(pi, args || "", ctx),
286		});
287		pi.registerCommand("git", {
288			description: "Alias for /worktrees",
289			handler: async (args, ctx) => showGitBrowser(pi, args || "", ctx),
290		});
291	}

