434					const { stdout } = await execFileAsync(
435						"git",
436						["-C", ctx.cwd, "diff", "--", file],
437						{ timeout: 5000 },
438					);
439					const lines = stdout.split("\n");
440					const GREEN = "\x1b[38;5;150m";
441					const RED = "\x1b[38;5;210m";
442					const DIM = "\x1b[38;5;60m";
443					const RST = "\x1b[0m";
444					const rendered = lines.map((line) => {
445						if (
446							line.startsWith("+++") ||
447							line.startsWith("---") ||
448							line.startsWith("@@") ||
449							line.startsWith("diff ")
450						) {
451							return `${DIM}${line}${RST}`;
452						}
453						if (line.startsWith("+")) return `${GREEN}${line}${RST}`;
454						if (line.startsWith("-")) return `${RED}${line}${RST}`;
455						return `${DIM}${line}${RST}`;
456					});
457					if (ctx.hasUI && ctx.mode === "tui") {
458						const { truncateToWidth } = await import("@earendil-works/pi-tui");
459						const truncated = rendered.map((l: string) =>
460							truncateToWidth(l, process.stdout.columns || 80),
461						);
462						ctx.ui.setWidget("pi-diff", truncated.slice(0, 50));
463					} else {
464						ctx.ui.notify(rendered.slice(0, 20).join("\n"), "info");
465					}

