624	function parseCommandArgs(args: string): CreateNoteParams {
625		const parts = (args || "").trim().split(/\s+/).filter(Boolean);
626		const kind = (
627			["spec", "plan", "design", "arch", "pr", "review", "note"].includes(
628				parts[0],
629			)
630				? parts.shift()
631				: "note"
632		) as NoteKind;
633		let contextMode: ContextMode | undefined;
634		let entryCount: number | undefined;
635		let openAfter = true;
636		const titleParts: string[] = [];
637		for (let i = 0; i < parts.length; i++) {
638			const part = parts[i];
639			if (part === "--full") contextMode = "full";
640			else if (part === "--since-compaction") contextMode = "since-compaction";
641			else if (part === "--no-open") openAfter = false;
642			else if (part === "--n") {
643				contextMode = "n-entries";
644				entryCount = Number(parts[++i] || 30);
645			} else titleParts.push(part);
646		}
647		const title = titleParts.join(" ").trim() || undefined;
648		return { kind, title, slug: title, contextMode, entryCount, openAfter };
649	}
