543		const context = summarizeEntries(entries, cfg, params);
544		const template = existing ? "" : await readTemplate(kind);
545		const artifact = await maybeReadArtifact(ctx.cwd, params);
546		const branch = await currentBranch(ctx.cwd);
547		const head = await currentHead(ctx.cwd);
548		let content = existing
