651	function inferIntent(prompt: string): NoteKind | undefined {
652		const p = prompt.toLowerCase();
653		if (/\b(review|pr review|diff review)\b/.test(p)) return "review";
654		if (/\b(plan|planning|implementation plan)\b/.test(p)) return "plan";
655		if (/\b(spec|specification|prd)\b/.test(p)) return "spec";
656		if (/\bdesign\b/.test(p)) return "design";
657		if (/\barch|architecture\b/.test(p)) return "arch";
658		return undefined;
659	}
