353		const dir = join(root, "worktree-backups", stamp);
354		await mkdir(dir, { recursive: true });
355		const [status, diff, staged, head, branch] = await Promise.all([
356			execCmd("git", ["-C", worktreePath, "status", "--porcelain=v1"], worktreePath, 5000),
357			execCmd("git", ["-C", worktreePath, "diff"], worktreePath, 10000),
358			execCmd("git", ["-C", worktreePath, "diff", "--cached"], worktreePath, 10000),
359			currentHead(worktreePath),
