361		]);
362		await writeFile(join(dir, "status.txt"), status.stdout || "(clean)\n");
363		await writeFile(join(dir, "diff.patch"), diff.stdout || "");
364		await writeFile(join(dir, "staged.patch"), staged.stdout || "");
365		const untracked = status.stdout.split("\n").filter((line) => line.startsWith("?? ")).map((line) => line.slice(3));
366		await writeFile(join(dir, "untracked.txt"), untracked.join("\n") + (untracked.length ? "\n" : ""));
367		if (untracked.length) {
368			await writeFile(join(dir, "untracked-files.txt"), untracked.join("\n") + "\n");
369			await execCmd("tar", ["-czf", join(dir, "untracked.tgz"), "-T", join(dir, "untracked-files.txt")], worktreePath, 15000);
370		}
371		await writeFile(
372			join(dir, "metadata.json"),
373			JSON.stringify(
374				{
