376					worktreePath,
377					branch,
378					head,
379					sourceSession,
380					statusCount: status.stdout.split("\n").filter(Boolean).length,
381					untrackedCount: untracked.length,
382				},
383				null,
384				2,
385			) + "\n",
386		);
387		return dir;
388	}
